class Solution:
    def countOfAtoms(self, formula: str) -> str:
        i, n = 0, len(formula)
        stack = [{}]
        while i < n:
            if formula[i] == '(':
                stack.append({})
                i += 1
            elif formula[i] == ')':
                top = stack.pop()
                i += 1
                start = i
                while i < n and formula[i].isdigit():
                    i += 1
                multiplier = int(formula[start:i] or 1)
                for name, count in top.items():
                    stack[-1][name] = stack[-1].get(name, 0) + count * multiplier
            else:
                start = i
                i += 1
                while i < n and formula[i].islower():
                    i += 1
                name = formula[start:i]
                start = i
                while i < n and formula[i].isdigit():
                    i += 1
                count = int(formula[start:i] or 1)
                stack[-1][name] = stack[-1].get(name, 0) + count
        result = []
        for name in sorted(stack[-1]):
            result.append(name)
            if stack[-1][name] > 1:
                result.append(str(stack[-1][name]))
        return ''.join(result)
